pub fn register_provider<T: LanguageModelProvider + LanguageModelProviderState>(
    &mut self,
    provider: Arc<T>,
    cx: &mut Context<Self>,
) {
    let subscription = provider.subscribe(cx, {
        let id = id.clone();
        move |_, cx| {
            cx.emit(Event::ProviderStateChanged(id.clone()));
        }
    });
    self.providers.insert(id.clone(), provider);
    cx.emit(Event::AddedProvider(id));
}

pub fn visible_providers(&self) -> Vec<Arc<dyn LanguageModelProvider>> {
    self.providers().into_iter().filter(|provider| {
        if let Some(hiding_fn) = &self.builtin_provider_hiding_fn {
            for extension_id in &self.installed_llm_extension_ids {
                if let Some(hidden_provider_id) = hiding_fn(extension_id) {
                    if provider.id().0 == hidden_provider_id { return false; }
                }
            }
        }
        true
    }).collect()
}

