pub fn bindings_for_input(
    &self,
    input: &[impl AsKeystroke],
    context_stack: &[KeyContext],
) -> (SmallVec<[KeyBinding; 1]>, bool) {
    let mut matched_bindings = SmallVec::<[(usize, BindingIndex, &KeyBinding); 1]>::new();
    let mut pending_bindings = SmallVec::<[(BindingIndex, &KeyBinding); 1]>::new();

    for (ix, binding) in self.bindings().enumerate().rev() {
        let Some(depth) = self.binding_enabled(binding, context_stack) else { continue };
        let Some(pending) = binding.match_keystrokes(input) else { continue };

        if !pending {
            matched_bindings.push((depth, BindingIndex(ix), binding));
        } else {
            pending_bindings.push((BindingIndex(ix), binding));
        }
    }

    matched_bindings.sort_by(|(depth_a, ix_a, _), (depth_b, ix_b, _)| {
        depth_b.cmp(depth_a).then(ix_b.cmp(ix_a))
    });

    let mut bindings: SmallVec<[_; 1]> = SmallVec::new();
    for (_, ix, binding) in matched_bindings {
        if is_no_action(&*binding.action) {
            break;
        }
        bindings.push(binding.clone());
    }

    (bindings, !pending.is_empty())
}

pub trait UserSettingsContentExt {
    fn for_profile(&self, cx: &App) -> Option<&SettingsContent>;
    fn for_release_channel(&self) -> Option<&SettingsContent>;
    fn for_os(&self) -> Option<&SettingsContent>;
}

impl UserSettingsContentExt for UserSettingsContent {
    fn for_profile(&self, cx: &App) -> Option<&SettingsContent> {
        let Some(active_profile) = cx.try_global::<ActiveSettingsProfileName>() else {
            return None;
        };
        self.profiles.get(&active_profile.0)
    }

    fn for_release_channel(&self) -> Option<&SettingsContent> {
        match *release_channel::RELEASE_CHANNEL {
            ReleaseChannel::Dev => self.dev.as_deref(),
            ReleaseChannel::Nightly => self.nightly.as_deref(),
            ReleaseChannel::Preview => self.preview.as_deref(),
            ReleaseChannel::Stable => self.stable.as_deref(),
        }
    }

    fn for_os(&self) -> Option<&SettingsContent> {
        match env::consts::OS {
            "macos" => self.macos.as_deref(),
            "linux" => self.linux.as_deref(),
            "windows" => self.windows.as_deref(),
            _ => None,
        }
    }
}

